import { Col, Form, Row, Splitter } from "antd"
import { useEffect, useState } from "react"
import { useSelector } from "react-redux"
import Delete from "src/components/Modal/Delete"
import TitleCustom from "src/components/TitleCustom"
import { GUIDE_EMPTY } from "src/constants/constants"
import { removeDiacritics } from "src/lib/stringsUtils"
import AssociationService from "src/services/AssociationService"
import AssociationForm from "./components/AssociationForm"
import ListAssociation, { sort } from "./ListAssociation/ListAssociation"
import { AssociationStyle } from "./styled"

const Association = () => {
  const [form] = Form.useForm()
  const [selectedNode, setSelectedNote] = useState()
  const { listSystemKey } = useSelector(state => state.appGlobal)
  const [pagination, setPagination] = useState({
    PageSize: 10,
    CurrentPage: 1,
    Status: 1,
    MemberType: 1,
    AssociationID: GUIDE_EMPTY,
  })
  const [loading, setLoading] = useState(false)
  const [newAssoc, setNewAssoc] = useState(false)
  const [openModalDelete, setOpenModalDelete] = useState(undefined)

  const [treeData, setTreeData] = useState([])

  const nest = (items, id, link) => {
    return items
      ?.filter(item => item[link] === id)
      .map(item => ({
        ...item,
        title: item.title,
        key: item.key,
        value: item.key,
        children: nest(items, item?.key, link),
      }))
  }

  const getListAssoc = async () => {
    try {
      setLoading(true)
      const res = await AssociationService.getAssociationNameList({
        AssociationID: GUIDE_EMPTY,
        AssociationName: "",
      })
      if (res?.isError) return
      const dataList = sort(
        res?.Object?.map(item => ({
          ...item,
          key: item?.AssociationID,
          title: item?.AssociationName || "",
          removeDiacriticsTitle: removeDiacritics(
            item?.AssociationName.toLowerCase(),
          ),
        })),
      )

      const tree = nest(sort(dataList), GUIDE_EMPTY, "ParentID")

      setTreeData({ tree: tree, dataList: dataList })
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    getListAssoc()
  }, [])

  useEffect(() => {
    setPagination(pre => ({
      ...pre,
      AssociationID: selectedNode?.key,
    }))
  }, [selectedNode])

  return (
    <AssociationStyle>
      <TitleCustom>Danh sách hiệp hội</TitleCustom>
      <Row gutter={[16, 16]}>
        <Splitter>
          <Splitter.Panel defaultSize="35%" min="15%" max="35%">
            <Col style={{ width: 600 }}>
              <ListAssociation
                selectedNode={selectedNode}
                setSelectedNote={setSelectedNote}
                treeData={treeData}
              />
            </Col>
          </Splitter.Panel>
          <Splitter.Panel>
            <Col flex="auto">
              <div className="detail-box">
                <div>
                  <AssociationForm
                    treeData={treeData}
                    onOk={() => {
                      getListAssoc()
                    }}
                    selectedNode={selectedNode}
                    setSelectedNote={setSelectedNote}
                  />
                </div>
              </div>
            </Col>
          </Splitter.Panel>
        </Splitter>
      </Row>
      {openModalDelete && (
        <Delete
          isOpen={!!openModalDelete}
          content={{
            title: (
              <div className="fw-600 text-center" style={{ fontSize: 16 }}>
                Bạn có chắc chắn muốn xóa thành viên "
                <b>{openModalDelete?.FullName}</b>" không?
              </div>
            ),
          }}
          onOk={() => {
            setOpenModalDelete(undefined)
          }}
          onCancel={() => setOpenModalDelete(undefined)}
        />
      )}
    </AssociationStyle>
  )
}

export default Association
