import { Avatar, Col, Divider, Form, Row, Select } from "antd"
import dayjs from "dayjs"
import { useEffect, useState } from "react"
import { useSelector } from "react-redux"
import DatePickerCustom from "src/components/Date/DatePickerCustom"
import InputCustom from "src/components/Input/InputCustom"
import CB1 from "src/components/Modal/CB1"
import ButtonCustom from "src/components/MyButton/Button"
import notice from "src/components/Notice"
import SelectCustom from "src/components/Select/SelectCustom"
import TreeSelectCustom from "src/components/Select/TreeSelectCustom"
import { GUIDE_ONE, SYSTEM_KEY } from "src/constants/constants"
import {
  getRegexEmail,
  getRegexMobile,
  removeDiacritics,
} from "src/lib/stringsUtils"
import { getListComboByKey } from "src/lib/utils"
import AssociationService from "src/services/AssociationService"
import MemberService from "src/services/MemberService"

const AssociationForm = ({
  treeData,
  selectedNode,
  setSelectedNote,
  setLoading = () => {},
  onOk = () => {},
}) => {
  const { listSystemKey } = useSelector(state => state.appGlobal)
  const [form] = Form.useForm()
  const isEdit = selectedNode?.key
  const [detail, setDetail] = useState(undefined)
  const [listPresident, setListPresident] = useState([])

  const success = () => {
    setSelectedNote(undefined)
    onOk()
    form.resetFields()
    setDetail(undefined)
  }

  const getListPresident = async () => {
    try {
      setLoading(true)
      const res = await MemberService.getAllMemberForCategory({})
      console.log("res", res)
      if (res?.isError) return

      // Xử lý dữ liệu từ API mới
      const presidentList =
        res?.Object?.map(item => ({
          UserID: item.UserID,
          Name: item.Name,
        })) || []

      setListPresident(presidentList)
    } finally {
      setLoading(false)
    }
  }

  const handleCreateUpdateAssoc = async () => {
    try {
      setLoading(true)
      const values = await form.validateFields()
      console.log("values", values)

      let res = await AssociationService[
        isEdit ? "updateAssociation" : "createAssociationAdmin"
      ]({
        ...values,
        AssociationID: isEdit ? selectedNode?.key : undefined,
        EstablishmentDate: values?.EstablishmentDate.format(),
        LeaderID: values?.LeaderName || "",
        IsDelete: false,
      })
      console.log("res", res)
      if (res?.isError) return
      notice({
        msg: `${isEdit ? "Cập nhật" : "Thêm"} hiệp hội thành công !`,
      })
      success()
    } finally {
      setLoading(false)
    }
  }

  const handleDeleteAssoc = () => {
    CB1({
      title: `Bạn có chắc chắn muốn xoá
              ' <strong> ${detail?.AssociationName}</strong> ' không?`,
      icon: "trashRed",
      okText: "Đồng ý",
      onOk: async close => {
        onDeleteCategory(selectedNode?.key)
        close()
      },
    })
  }

  const onDeleteCategory = async id => {
    try {
      setLoading(true)
      const res = await AssociationService.deleteAssociation({
        AssociationId: id,
      })
      if (res?.isError) return
      notice({ msg: "Xóa hiệp hội thành công!" })
      success()
    } finally {
      setLoading(false)
    }
  }

  const getDetailAssoc = async () => {
    try {
      setLoading(true)
      let res = await AssociationService.getAssociationDetail({
        associationId: selectedNode?.key,
      })
      if (res?.isError) return
      const values = res?.Object
      form.setFieldsValue({
        ...values,
        EstablishmentDate: values?.EstablishmentDate
          ? dayjs(values?.EstablishmentDate)
          : undefined,
        Status: values?.Status,
        Name: values?.AssociationName,
        LeaderID: values?.LeaderID,
      })
      setDetail(res?.Object)
    } catch (error) {
      console.log("error", error)
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    if (!selectedNode?.key) return
    getDetailAssoc()
  }, [selectedNode])

  // Gọi API lấy danh sách hội trưởng khi component mount
  useEffect(() => {
    getListPresident()
  }, [])

  return (
    <Form
      form={form}
      layout="vertical"
      initialValues={{
        SortOrder: 0,
        Status: 1,
        AssociationType: 1,
        ParentId: GUIDE_ONE,
        EstablishmentDate: dayjs(),
      }}
    >
      {selectedNode?.key ? (
        <div className="text-center fw-600 fs-24 mb-16">
          Cập nhật thông tin hiệp hội{" "}
        </div>
      ) : (
        <div className="text-center fw-600 fs-24 mb-16">Thêm mới hiệp hội </div>
      )}{" "}
      <Row gutter={(8, 8)}>
        <Col span={selectedNode?.key ? 8 : 0}>
          {!!selectedNode?.key && (
            <div className="text-center">
              <Avatar
                size={164}
                src={
                  detail?.Image ? (
                    <img src={detail?.Image} alt="avatar" />
                  ) : undefined
                }
                style={{
                  backgroundColor: "#7265e6",
                  verticalAlign: "middle",
                  boxShadow: "1px 4px 10px rgba(0,0,0,0.3)",
                  fontSize: "5rem",
                }}
                className="mb-8"
              >
                {detail?.AssociationName[0]}
              </Avatar>
              <div>Mã hội: {detail?.AssociationCode}</div>
              <div>Số hội viên: {detail?.MemberNo || 0} </div>
            </div>
          )}
        </Col>
        <Col span={selectedNode?.key ? 16 : 24}>
          <Row gutter={16}>
            <Col span={24}>
              <Form.Item
                label="Tên hội"
                name="Name"
                rules={[
                  {
                    required: true,
                    message: "Thông tin không được để trống",
                  },
                ]}
              >
                <InputCustom placeholder="Nhập họ tên" />
              </Form.Item>
            </Col>
            <Col span={24}>
              <Form.Item
                label="Hội trực thuộc"
                name="ParentId"
                rules={[
                  {
                    required: true,
                    message: "Thông tin không được để trống",
                  },
                ]}
              >
                <TreeSelectCustom
                  showSearch
                  style={{ width: "100%" }}
                  styles={{
                    popup: { root: { maxHeight: 400, overflow: "auto" } },
                  }}
                  placeholder="Chọn"
                  allowClear
                  treeDefaultExpandAll
                  treeData={treeData?.tree}
                  filterTreeNode={(input, treeNode) => {
                    const title = removeDiacritics(treeNode.title.toLowerCase())
                    const searchValue = removeDiacritics(input.toLowerCase())
                    const result = title.indexOf(searchValue) !== -1
                    return result
                  }}
                />
              </Form.Item>
            </Col>
            <Col span={8}>
              <Form.Item
                label="Email"
                name="Email"
                rules={[
                  {
                    required: true,
                    pattern: getRegexEmail(),
                    message: "Email không hợp lệ",
                  },
                ]}
              >
                <InputCustom placeholder="Nhập" />
              </Form.Item>
            </Col>
            <Col span={8}>
              <Form.Item
                label="Hội trưởng"
                name="LeaderName"
                rules={[
                  {
                    required: true,
                    message: "Vui lòng chọn hội trưởng",
                  },
                ]}
              >
                <SelectCustom placeholder="Chọn hội trưởng" showSearch>
                  {listPresident.map(member => (
                    <Select.Option key={member.UserID} value={member.UserID}>
                      {member.Name}
                    </Select.Option>
                  ))}
                </SelectCustom>
              </Form.Item>
            </Col>
            <Col span={8}>
              <Form.Item
                label="Trạng thái"
                name="Status"
                rules={[
                  {
                    required: true,
                    message: "Thông tin không được để trống",
                  },
                ]}
              >
                <SelectCustom placeholder="Chọn ">
                  {getListComboByKey(
                    SYSTEM_KEY?.ASSOCIATION_STATUS,
                    listSystemKey,
                  )?.map(i => (
                    <Select.Option key={+i.CodeValue} value={+i.CodeValue}>
                      {i?.Description}
                    </Select.Option>
                  ))}
                </SelectCustom>
              </Form.Item>
            </Col>
          </Row>
        </Col>
        {!!selectedNode?.key && <Divider />}

        <Col span={6}>
          <Form.Item
            label="Số điện thoại"
            name="PhoneNumber"
            rules={[
              {
                required: true,
                pattern: getRegexMobile(),
                message: "Số điện thoại là chuỗi từ 10 đến 11 kí tự chữ số",
              },
            ]}
          >
            <InputCustom placeholder="Nhập" />
          </Form.Item>
        </Col>
        <Col span={6}>
          <Form.Item
            label="Ngày thành lập"
            name="EstablishmentDate"
            rules={[
              {
                required: true,
                message: "Thông tin không được để trống",
              },
            ]}
          >
            <DatePickerCustom
              disabledDate={current => current && current > dayjs()}
              placeholder="Nhập"
              format="DD/MM/YYYY"
            />
          </Form.Item>
        </Col>
        <Col span={6}>
          <Form.Item
            label="Sắp xếp"
            name="SortOrder"
            rules={[
              {
                required: true,
                message: "Thông tin không được để trống",
              },
            ]}
          >
            <InputCustom type="number" placeholder="Nhập" />
          </Form.Item>
        </Col>
        <Col span={6}>
          <Form.Item
            label="Loại hội"
            name="AssociationType"
            rules={[
              {
                required: true,
                message: "Thông tin không được để trống",
              },
            ]}
          >
            <SelectCustom placeholder="Chọn">
              {getListComboByKey(
                SYSTEM_KEY?.ASSOCIATION_TYPE,
                listSystemKey,
              )?.map(i => (
                <Select.Option key={+i.CodeValue} value={+i.CodeValue}>
                  {i?.Description}
                </Select.Option>
              ))}
            </SelectCustom>
          </Form.Item>
        </Col>
        <Col span={24}>
          <Form.Item
            label="Địa chỉ"
            name="Address"
            rules={[
              {
                required: true,
                message: "Thông tin không được để trống",
              },
            ]}
          >
            <InputCustom placeholder="Nhập" />
          </Form.Item>
        </Col>
        <Col span={24} className="d-flex-end">
          {!!selectedNode?.key && (
            <ButtonCustom className="mr-8" onClick={() => handleDeleteAssoc()}>
              Xóa
            </ButtonCustom>
          )}
          <ButtonCustom
            className="mr-8"
            onClick={() => handleCreateUpdateAssoc()}
          >
            Ghi lại
          </ButtonCustom>

          {/* <ButtonCustom
            onClick={() => {
              setSelectedNote(undefined)
            }}
          >
            Đặt lại
          </ButtonCustom> */}
        </Col>
      </Row>
    </Form>
  )
}

export default AssociationForm
